import { getAppTimeZone } from '../services/app-timezone.service.js';

/**
 * Human-readable "when was this coaching note generated" label, in the app's
 * local timezone. Shared by the coaching screen (`/health/coaching`) and the
 * dashboard coaching card so both phrase the stamp identically.
 *
 * `today` is the app-local `YYYY-MM-DD` the caller is comparing against
 * (`appTodayString()`), passed in so the formatter stays pure.
 */
export function formatRelativeStamp(generatedAt: string | null, today: string): string {
    if (!generatedAt) return '';
    try {
        const generated = Temporal.Instant.from(generatedAt);
        const generatedZoned = generated.toZonedDateTimeISO(getAppTimeZone());
        const generatedDate = generatedZoned.toPlainDate().toString();
        if (generatedDate === today) {
            return `Generated today at ${generatedZoned.toPlainTime().toString({ smallestUnit: 'minute' })}`;
        }
        return `Generated on ${generatedDate}`;
    } catch {
        return `Generated at ${generatedAt}`;
    }
}
